/**
 * @summary 记录复习结果并更新SM-2参数
 */
export const getLogReviewUrl = () => {
  return `/api/reviews/log`;
};

export const logReview = async (
  logReviewRequest: LogReviewRequest,
  options?: RequestInit,
): Promise<ReviewLogResponse> => {
  return customFetch<ReviewLogResponse>(getLogReviewUrl(), {
    ...options,
    method: "POST",
    headers: { "Content-Type": "application/json", ...options?.headers },
    body: JSON.stringify(logReviewRequest),
  });
};

export const getLogReviewMutationOptions = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof logReview>>,
    TError,
    { data: BodyType<LogReviewRequest> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof logReview>>,
  TError,
  { data: BodyType<LogReviewRequest> },
  TContext
> => {
  const mutationKey = ["logReview"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof logReview>>,
    { data: BodyType<LogReviewRequest> }
  > = (props) => {
    const { data } = props ?? {};

    return logReview(data, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

export type LogReviewMutationResult = NonNullable<
  Awaited<ReturnType<typeof logReview>>
>;
export type LogReviewMutationBody = BodyType<LogReviewRequest>;
export type LogReviewMutationError = ErrorType<unknown>;

/**
 * @summary 记录复习结果并更新SM-2参数
 */
export const useLogReview = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof logReview>>,
    TError,
    { data: BodyType<LogReviewRequest> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationResult<
  Awaited<ReturnType<typeof logReview>>,
  TError,
  { data: BodyType<LogReviewRequest> },
  TContext
> => {
  return useMutation(getLogReviewMutationOptions(options));
};

/**
 * @summary 获取学习热力图数据
 */
export const getGetHeatmapDataUrl = () => {
  return `/api/analytics/heatmap`;
};

export const getHeatmapData = async (
  options?: RequestInit,
): Promise<HeatmapResponse> => {
  return customFetch<HeatmapResponse>(getGetHeatmapDataUrl(), {
    ...options,
    method: "GET",
  });
};

export const getGetHeatmapDataQueryKey = () => {
  return [`/api/analytics/heatmap`] as const;
};

export const getGetHeatmapDataQueryOptions = <
  TData = Awaited<ReturnType<typeof getHeatmapData>>,
  TError = ErrorType<unknown>,
>(options?: {
  query?: UseQueryOptions<
    Awaited<ReturnType<typeof getHeatmapData>>,
    TError,
    TData
  >;
  request?: SecondParameter<typeof customFetch>;
}) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getGetHeatmapDataQueryKey();

  const queryFn: QueryFunction<Awaited<ReturnType<typeof getHeatmapData>>> = ({
    signal,
  }) => getHeatmapData({ signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof getHeatmapData>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type GetHeatmapDataQueryResult = NonNullable<
  Awaited<ReturnType<typeof getHeatmapData>>
>;
export type GetHeatmapDataQueryError = ErrorType<unknown>;

/**
 * @summary 获取学习热力图数据
 */

export function useGetHeatmapData<
  TData = Awaited<ReturnType<typeof getHeatmapData>>,
  TError = ErrorType<unknown>,
>(options?: {
  query?: UseQueryOptions<
    Awaited<ReturnType<typeof getHeatmapData>>,
    TError,
    TData
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getGetHeatmapDataQueryOptions(options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}
